item.content:encoded:
.nv-contact-list {
    list-style: none;
    padding: 0;
    margin: 0;
}
.nv-contact-list.left {
    display: block; /* Assure l'affichage en colonne */
}

.nv-contact-list li {
    display: flex; /* Utiliser flex pour aligner l'icône et le texte sur une ligne */
    align-items: center; /* Centrer verticalement */
    gap: 8px; /* Espace entre l'icône et le texte */
    margin-bottom: 10px;
}

.nv-contact-list .icon {
    display: flex; /* Permet un bon alignement des icônes */
    justify-content: center;
    align-items: center;
}

.nv-contact-list a {
    text-decoration: none;
    color: #007bff;
    font-size: 16px; /* Taille du texte */
    line-height: 1.5; /* Hauteur de ligne pour un alignement vertical fluide */
}

.nv-contact-list a:hover {
    text-decoration: underline;
    color: #0056b3;
}

.nv-contact-list svg {
    fill: #007bff;
    width: 20px;
    height: 20px;
}
